parameters.text:
=You are an expert social media trend researcher. Research and analyze current trends for the following topic.

Topic: {{ $json.topic }}
Industry: {{ $json.industry }}
Target Audience: {{ $json.targetAudience }}

Your task:
1. Identify the top 3-5 trending angles, talking points, or developments for this topic RIGHT NOW
2. Extract compelling statistics, quotes, or data points that would resonate on social media
3. Identify the emotional hooks and narratives that are gaining traction
4. Compile platform-appropriate hashtags:
   - LinkedIn hashtags (3-5, professional/industry focused)
   - X/Twitter hashtags (2-3, trending/broad reach)
   - Instagram hashtags (10-15, mix of niche and broad)

Respond ONLY with a valid JSON object in this exact structure:
{
  "trendReport": {
    "topic": "string",
    "industry": "string",
    "researchTimestamp": "ISO 8601 string",
    "topTrends": [
      {
        "trendTitle": "string",
        "description": "string (2-3 sentences)",
        "relevanceScore": "number 1-10",
        "dataPoint": "string (stat or quote if available)"
      }
    ],
    "keyInsights": ["insight 1", "insight 2", "insight 3"],
    "contentAngles": ["angle 1", "angle 2", "angle 3"],
    "hashtags": {
      "linkedin": ["#hashtag1", "#hashtag2", "#hashtag3"],
      "twitter": ["#hashtag1", "#hashtag2"],
      "instagram": ["#hashtag1", "#hashtag2", "#hashtag3", "#hashtag4", "#hashtag5", "#hashtag6", "#hashtag7", "#hashtag8", "#hashtag9", "#hashtag10"]
    },
    "researchStatus": "success"
  }
}

parameters.jsCode:
// Parse Agent 1 JSON output and validate structure
const item = $input.item.json;
let trendReport;

try {
  // Agent may return the JSON in .output or .text
  const rawText = item.output || item.text || item.response || '';
  const cleaned = rawText.replace(/```json|```/g, '').trim();
  const parsed = JSON.parse(cleaned);
  trendReport = parsed.trendReport || parsed;

  // Validate required fields
  if (!trendReport.topTrends || !trendReport.hashtags) {
    throw new Error('Missing required fields in trend report');
  }

  return {
    json: {
      ...item,
      trendReport,
      agent1Status: 'success',
      agent1Timestamp: new Date().toISOString()
    }
  };
} catch (err) {
  // Fallback: construct a minimal report from available data
  return {
    json: {
      ...item,
      trendReport: {
        topic: item.topic || 'General',
        industry: item.industry || 'Technology',
        researchTimestamp: new Date().toISOString(),
        topTrends: [{
          trendTitle: item.topic + ' Latest Developments',
          description: 'Key developments are shaping the ' + (item.industry || 'industry') + ' landscape.',
          relevanceScore: 7,
          dataPoint: 'Industry leaders are actively investing in this area.'
        }],
        keyInsights: ['Innovation is accelerating', 'Adoption rates are rising', 'New use cases emerging'],
        contentAngles: ['Educational', 'Thought leadership', 'Industry news'],
        hashtags: {
          linkedin: ['#Innovation', '#' + (item.industry || 'Technology'), '#Leadership'],
          twitter: ['#' + (item.topic || 'Tech').replace(/\s/g, ''), '#Innovation'],
          instagram: ['#innovation', '#tech', '#business', '#growth', '#future', '#digital', '#strategy', '#success', '#entrepreneurship', '#ai']
        },
        researchStatus: 'fallback'
      },
      agent1Status: 'fallback',
      agent1Error: err.message,
      agent1Timestamp: new Date().toISOString()
    }
  };
}

parameters.text:
=You are an expert social media copywriter and content strategist. Using the trend research provided, create platform-optimized social media content.

Trend Report:
{{ JSON.stringify($json.trendReport, null, 2) }}

Brand Voice: {{ $json.brandVoice || 'Professional, insightful, forward-thinking' }}
Target Audience: {{ $json.targetAudience || 'Business professionals and tech enthusiasts' }}

Create platform-specific captions AND image generation prompts.

Platform requirements:
- LINKEDIN: ≤3000 chars, professional tone, storytelling hook, 3-5 hashtags at end, no emojis in first line
- TWITTER/X: ≤280 chars (strict), punchy/bold opening, 2-3 inline hashtags, optionally 1 emoji
- INSTAGRAM: ≤2200 chars, conversational and engaging, strong hook, call-to-action, 10-15 hashtags in first comment section

For EACH platform also generate a DALL-E image prompt (photorealistic or modern graphic style, no text in image).

Respond ONLY with a valid JSON object in this exact structure:
{
  "contentBundle": {
    "generationTimestamp": "ISO 8601 string",
    "topic": "string",
    "linkedin": {
      "caption": "string (≤3000 chars)",
      "hashtags": ["#tag1", "#tag2"],
      "imagePrompt": "string (detailed DALL-E prompt)",
      "characterCount": 0
    },
    "twitter": {
      "caption": "string (≤280 chars STRICT)",
      "hashtags": ["#tag1", "#tag2"],
      "imagePrompt": "string (detailed DALL-E prompt)",
      "characterCount": 0
    },
    "instagram": {
      "caption": "string (≤2200 chars)",
      "firstCommentHashtags": "string (all hashtags as single string for first comment)",
      "imagePrompt": "string (detailed DALL-E prompt)",
      "characterCount": 0
    },
    "contentStatus": "success"
  }
}

parameters.jsCode:
// Parse Agent 2 JSON output, validate structure, and enforce character limits
const item = $input.item.json;
let contentBundle;

try {
  const rawText = item.output || item.text || item.response || '';
  const cleaned = rawText.replace(/```json|```/g, '').trim();
  const parsed = JSON.parse(cleaned);
  contentBundle = parsed.contentBundle || parsed;

  // Validate required platform keys
  if (!contentBundle.linkedin || !contentBundle.twitter || !contentBundle.instagram) {
    throw new Error('Missing platform content in content bundle');
  }

  // Enforce Twitter 280-char hard limit
  if (contentBundle.twitter.caption && contentBundle.twitter.caption.length > 280) {
    contentBundle.twitter.caption = contentBundle.twitter.caption.substring(0, 277) + '...';
  }

  // Update character counts
  contentBundle.linkedin.characterCount = (contentBundle.linkedin.caption || '').length;
  contentBundle.twitter.characterCount = (contentBundle.twitter.caption || '').length;
  contentBundle.instagram.characterCount = (contentBundle.instagram.caption || '').length;

  // Validate image prompts exist
  const imageFailed = !contentBundle.linkedin.imagePrompt || !contentBundle.twitter.imagePrompt || !contentBundle.instagram.imagePrompt;

  return {
    json: {
      ...item,
      contentBundle,
      imageFailed,
      agent2Status: 'success',
      agent2Timestamp: new Date().toISOString()
    }
  };
} catch (err) {
  return {
    json: {
      ...item,
      contentBundle: null,
      imageFailed: true,
      agent2Status: 'error',
      agent2Error: err.message,
      agent2Timestamp: new Date().toISOString()
    }
  };
}

// Merge image URLs from all three DALL-E calls back into the content bundle
// NOTE: In n8n this node receives the last item; use $('node-name').all() pattern
// to merge. Here we enrich with image URLs assuming they're in scope.
const item = $input.item.json;

const linkedinImageUrl = item.linkedinImageData?.data?.[0]?.url || item.contentBundle?.linkedin?.imagePrompt || null;
const twitterImageUrl = item.twitterImageData?.data?.[0]?.url || item.contentBundle?.twitter?.imagePrompt || null;
const instagramImageUrl = item.instagramImageData?.data?.[0]?.url || item.contentBundle?.instagram?.imagePrompt || null;

return {
  json: {
    ...item,
    contentBundle: {
      ...item.contentBundle,
      linkedin: { ...item.contentBundle.linkedin, imageUrl: linkedinImageUrl },
      twitter: { ...item.contentBundle.twitter, imageUrl: twitterImageUrl },
      instagram: { ...item.contentBundle.instagram, imageUrl: instagramImageUrl }
    },
    imagesReady: !!(linkedinImageUrl && twitterImageUrl && instagramImageUrl),
    imagesMergeTimestamp: new Date().toISOString()
  }
};

// Collect results from all three platform posts and build final status report
const item = $input.item.json;

const linkedinPostId = item.linkedinResult?.id || item.id || null;
const twitterPostId = item.twitterResult?.data?.id || item.data?.id || null;
const instagramPostId = item.instagramPublishResult?.id || item.id || null;

const linkedinStatus = linkedinPostId ? 'published' : (item.linkedinError ? 'failed' : 'unknown');
const twitterStatus = twitterPostId ? 'published' : (item.twitterError ? 'failed' : 'unknown');
const instagramStatus = instagramPostId ? 'published' : (item.instagramError ? 'failed' : 'unknown');

const publishedDate = new Date().toISOString().split('T')[0];
const publishedTimestamp = new Date().toISOString();

return {
  json: {
    ...item,
    publishReport: {
      requestId: item.requestId,
      topic: item.topic,
      publishedDate,
      publishedTimestamp,
      platforms: {
        linkedin: {
          status: linkedinStatus,
          postId: linkedinPostId,
          url: linkedinPostId ? 'https://www.linkedin.com/feed/update/' + linkedinPostId : null
        },
        twitter: {
          status: twitterStatus,
          postId: twitterPostId,
          url: twitterPostId ? 'https://x.com/i/web/status/' + twitterPostId : null
        },
        instagram: {
          status: instagramStatus,
          postId: instagramPostId
        }
      },
      overallStatus: [linkedinStatus, twitterStatus, instagramStatus].every(s => s === 'published')
        ? 'all_published'
        : [linkedinStatus, twitterStatus, instagramStatus].some(s => s === 'published')
          ? 'partial_success'
          : 'all_failed'
    }
  }
};

